steps.script:
var wb = GameState.state.units["U_WARBOSS_B"].models[0].position
var base = Vector2(float(wb.x) + 60.0, float(wb.y))
var ws = GameState.state.units["U_WITCHSEEKERS_C"].models
for i in range(ws.size()):
	ws[i]["position"] = {"x": base.x + (i % 3) * 40.0, "y": base.y + int(i / 3.0) * 40.0}
return ws.size()

var ph = PhaseManager.get_current_phase_instance()
for i in range(4):
	var r = ph.execute_action({"type": "END_PILE_IN"})
	if not r.get("success", false):
		break
return ph._subphase_string_11e()

var fc = tree.current_scene.fight_controller
var q = [fc.fight_selection_panel]
while not q.is_empty():
	var n = q.pop_front()
	if n is Button and str(n.name) == "Fight_U_WARBOSS_B":
		n.grab_focus()
	for c in n.get_children():
		q.append(c)
return str(tree.root.gui_get_focus_owner().name)

var dlg = null
for n in tree.root.get_children():
	if n is AcceptDialog and n.visible:
		dlg = n
if dlg == null:
	return "no epic"
var btn = null
var q = [dlg]
while not q.is_empty():
	var x = q.pop_front()
	if x is Button and str(x.text).to_lower().find("decline") != -1:
		btn = x
	for c in x.get_children():
		q.append(c)
if btn != null:
	btn.emit_signal("pressed")
	return "declined"
return "no decline"

var ad = tree.root.get_node_or_null("AttackAssignmentDialog")
for i in range(ad.weapon_list.item_count):
	if str(ad.weapon_list.get_item_text(i)).to_lower().find("klaw") != -1:
		ad.weapon_list.select(i)
var picked = ""
for i in range(ad.target_list.item_count):
	if str(ad.target_list.get_item_metadata(i)) == "U_WITCHSEEKERS_C":
		ad.target_list.select(i)
		picked = "U_WITCHSEEKERS_C"
return picked
